import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { Trophy, Heart, Headphones } from 'lucide-react';
import { useMusic } from '../../context/MusicContext'; // Import context để đồng bộ

const Ranking = () => {
  const [topSongs, setTopSongs] = useState([]);
  
  // Lấy favorites và hàm like từ Context
  const { favorites, toggleLikeGlobal } = useMusic();

  // Hàm lấy dữ liệu bảng xếp hạng
  const fetchRanking = () => {
    axios.get('http://localhost:5000/api/songs/ranking')
      .then(res => setTopSongs(res.data))
      .catch(err => console.error("Lỗi tải bảng xếp hạng:", err));
  };

  // QUAN TRỌNG: Mỗi khi 'favorites' thay đổi, gọi lại fetchRanking để cập nhật số liệu mới nhất
  useEffect(() => {
    fetchRanking();
  }, [favorites]); // Thêm favorites vào đây để tự động reload khi nhấn like

  return (
    <div style={rankPage}>
      <header style={rankHeader}>
        <Trophy size={80} color="#FFD700" />
        <h1 style={{fontSize: '40px', margin: '10px 0'}}>BẢNG XẾP HẠNG P2TUNES</h1>
        <p style={{color: '#b3b3b3'}}>Cập nhật dựa trên lượt nghe và yêu thích của cộng đồng</p>
      </header>

      <div style={rankList}>
        {topSongs.map((song, index) => {
          // Kiểm tra xem bài hát này người dùng đã like chưa
          const isLiked = favorites?.includes(song._id);

          return (
            <div key={song._id} style={rankItem(index)}>
              <div style={rankNumber(index)}>{index + 1}</div>
              
              <img src={`http://localhost:5000${song.imageUrl}`} style={rankImg} alt="" />
              
              <div style={{ flex: 1 }}>
                <div style={songName}>{song.title}</div>
                <div style={songArt}>{song.artist}</div>
              </div>

              <div style={statsContainer}>
                {/* Thống kê lượt nghe */}
                <div style={statItem}>
                  <Headphones size={16} color="#1db954" />
                  <span>{song.playCount || 0}</span>
                </div>

                {/* Thống kê lượt Like - Cho phép nhấn like trực tiếp tại đây */}
                <div 
                  style={{ ...statItem, cursor: 'pointer' }} 
                  onClick={() => toggleLikeGlobal(song._id)}
                >
                  <Heart 
                    size={16} 
                    fill={isLiked ? "#ff4d4d" : "none"} 
                    color={isLiked ? "#ff4d4d" : "#b3b3b3"} 
                    style={{ transition: '0.2s' }}
                  />
                  <span style={{ color: isLiked ? "#ff4d4d" : "#fff" }}>
                    {song.likes?.length || 0}
                  </span>
                </div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

/* --- Styles (Giữ nguyên phong cách của bạn) --- */
const rankPage = { padding: '60px', maxWidth: '900px', margin: '0 auto', color: '#fff', background: '#121212', minHeight: '100vh', paddingBottom: '120px' };
const rankHeader = { textAlign: 'center', marginBottom: '50px' };
const rankList = { background: '#181818', borderRadius: '15px', padding: '10px' };
const rankItem = (i) => ({ 
  display: 'flex', alignItems: 'center', padding: '15px 25px', borderBottom: '1px solid #282828',
  background: i === 0 ? 'linear-gradient(90deg, #2a2200, transparent)' : 'transparent'
});
const rankNumber = (i) => ({ 
  fontSize: '24px', fontWeight: 'bold', width: '50px', 
  color: i === 0 ? '#FFD700' : i === 1 ? '#C0C0C0' : i === 2 ? '#CD7F32' : '#555' 
});
const rankImg = { width: '50px', height: '50px', borderRadius: '4px', marginRight: '20px', objectFit: 'cover' };
const songName = { fontSize: '16px', fontWeight: '600' };
const songArt = { fontSize: '13px', color: '#b3b3b3' };
const statsContainer = { display: 'flex', gap: '30px', fontSize: '14px', fontWeight: 'bold' };
const statItem = { display: 'flex', alignItems: 'center', gap: '8px' };

export default Ranking;
